package main

import (
	"encoding/gob"
	"fmt"
	"os"
)

type User struct {
	ID      int
	Prefs   []string
	Perms   []string
}

func main() {
	// Create a new user session object
	user := &User{
		ID:      1,
		Prefs:   []string{"pref1", "pref2"},
		Perms:   []string{"perm1", "perm2"},
	}

	// Serialize the user session using gob encoding
	var buf bytes.Buffer
	enc := gob.NewEncoder(&buf)
	if err := enc.Encode(user); err != nil {
		fmt.Println("Error serializing user session:", err)
	}

	// Save the serialized user session to disk
	f, err := os.Create("session.gob")
	if err != nil {
		fmt.Println("Error creating file for session:", err)
	}
	defer f.Close()

	if _, err = f.Write(buf.Bytes()); err != nil {
		fmt.Println("Error writing to file:", err)
	}

	// Reload the serialized user session from disk
	var loadedUser User
	f, err = os.Open("session.gob")
	if err != nil {
		fmt.Println("Error opening file for session:", err)
	}
	defer f.Close()

	dec := gob.NewDecoder(f)
	if err := dec.Decode(&loadedUser); err != nil {
		fmt.Println("Error deserializing user session:", err)
	}

	// Print the deserialized user session
	fmt.Println(loadedUser)
}